<script setup lang="ts">
import {onMounted, ref} from "vue"
import type {BusinessOfferingSchemaDTO, BusinessOfferingResponseDTO, BusinessResourceConfigurationDTO} from "../../../contracts/index.ts"
import {userShellApi} from "../api/userShellApi.ts"
import AppButton from "../components/AppButton.vue"
import AppStatus from "../components/AppStatus.vue"
import BusinessPricingRuleEditor from "../components/BusinessPricingRuleEditor.vue"
import BusinessResourcePoolEditor from "../components/BusinessResourcePoolEditor.vue"
import BusinessServiceSetupStepper from "../components/BusinessServiceSetupStepper.vue"
import ContextSwitcher from "../components/ContextSwitcher.vue"
import TaskSurface from "../components/TaskSurface.vue"

const steps = ["Basics", "Time & capacity", "Customer inputs", "Pricing", "Resources", "Preview"]
const businessTemplates = [{name: "Hair salon", mode: "Exact appointment"}, {name: "Dog daycare", mode: "Shared capacity window"}, {name: "Cleaning company", mode: "Field service"}, {name: "Car wash", mode: "Capacity window"}, {name: "Painting company", mode: "Field service"}, {name: "Tutor", mode: "Exact appointment"}, {name: "Repair service", mode: "Field service"}, {name: "Fitness trainer", mode: "Exact appointment"}]
const selectedTemplate = ref("")
const selectTemplate = (template: {name: string; mode: string}) => { selectedTemplate.value = template.name }
const templateBillingUnit = ref("per appointment")
const templateCapacity = ref(1)
const templateQuestions = ref("Customer notes")
const currentStep = ref(0)
const offerings = ref<BusinessOfferingResponseDTO[]>([])
const offeringDraft = ref<BusinessOfferingResponseDTO | null>(null)
const schema = ref<BusinessOfferingSchemaDTO | null>(null)
const resources = ref<BusinessResourceConfigurationDTO | null>(null)
const selectedOfferingId = ref<number | null>(null)
const loading = ref(true)
const saving = ref(false)
const error = ref("")
const profileId = () => Number(sessionStorage.getItem("activeBusinessProfileId"))
const load = async () => { loading.value = true; error.value = ""; try { offerings.value = (await userShellApi.getBusinessOfferings()).items; selectedOfferingId.value = selectedOfferingId.value ?? offerings.value[0]?.id ?? null; await selectOffering(); if (profileId()) resources.value = await userShellApi.getBusinessResources(profileId()) } catch { error.value = "Could not load service configuration." } finally { loading.value = false } }
const selectOffering = async () => { if (!selectedOfferingId.value) return; offeringDraft.value = offerings.value.find(item => item.id === selectedOfferingId.value) ?? null; schema.value = await userShellApi.getBusinessOfferingSchema(selectedOfferingId.value) }
const saveOfferingRules = async () => { if (!offeringDraft.value) return; saving.value = true; try { await userShellApi.updateBusinessOffering(offeringDraft.value.id, offeringDraft.value as any); await load() } catch { error.value = "Could not save service rules." } finally { saving.value = false } }
const refreshResources = async () => { if (profileId()) resources.value = await userShellApi.getBusinessResources(profileId()) }
onMounted(() => void load())
</script>

<template>
  <section class="business-template-library" aria-label="Business templates"><header><h2>Start from a business template</h2><p>Templates are editable suggestions for capacity, customer inputs, pricing, resources, and default availability. Review before publishing.</p></header><div class="business-template-library__grid"><button v-for="template in businessTemplates" :key="template.name" type="button" :class="{selected: selectedTemplate === template.name}" @click="selectTemplate(template)"><strong>{{ template.name }}</strong><span>{{ template.mode }}</span></button></div><AppStatus v-if="selectedTemplate" :message="`${selectedTemplate} is ready for review in the steps below.`" tone="success" /></section>
  <section v-if="selectedTemplate" class="business-template-overrides" aria-label="Template overrides"><header><h2>Review {{ selectedTemplate }} defaults</h2><p>Override or remove suggested values before saving the offering.</p></header><div><label>Billing unit<select v-model="templateBillingUnit"><option>per appointment</option><option>per hour</option><option>per day</option><option>per quantity</option><option>quote required</option></select></label><label>Capacity<input v-model.number="templateCapacity" type="number" min="1"></label><label>Customer questions<input v-model="templateQuestions" placeholder="Remove or replace questions"></label></div><small>Customer preview uses the saved offering rules, not these temporary template defaults, until you apply them in the setup steps.</small></section>
  <TaskSurface mode="act" label="Service setup"><section class="service-setup"><header><p class="eyebrow">Business / Service setup</p><div class="service-setup__title-row"><div><h1>Configure a service</h1><p>Work through only the parts this offering needs. The customer preview stays available at the end.</p></div><ContextSwitcher v-if="offerings.length" :model-value="selectedOfferingId" :options="offerings.map(item => ({id: item.id, label: item.title}))" label="Offering" empty-label="Choose offering" @update:model-value="async value => { selectedOfferingId = value === null ? null : Number(value); await selectOffering() }" /></div></header><AppStatus v-if="loading" message="Loading service configuration." busy /><AppStatus v-else-if="error && !offeringDraft" :message="error" tone="error" retry @retry="load" /><template v-else-if="offeringDraft"><BusinessServiceSetupStepper :steps="steps" :current="currentStep" @select="currentStep = $event" /><section class="setup-panel"><template v-if="currentStep === 0"><h2>Service basics</h2><p>Define what the customer is booking and how it should appear.</p><label>Fulfillment mode<select v-model="offeringDraft.fulfillmentMode"><option value="EXACT_APPOINTMENT">Exact appointment</option><option value="CAPACITY_WINDOW">Shared capacity window</option><option value="FIELD_SERVICE">Field service</option><option value="ALL_DAY_STAY">All-day / stay</option></select></label></template><template v-else-if="currentStep === 1"><h2>Time and capacity</h2><p>These rules determine which slots can be shown.</p><div class="setup-grid"><label>Duration increment<input v-model.number="offeringDraft.durationIncrementMinutes" type="number" min="1"></label><label>Minimum quantity<input v-model.number="offeringDraft.minimumQuantity" type="number" min="1"></label><label>Maximum quantity<input v-model.number="offeringDraft.maximumQuantity" type="number" min="1"></label></div></template><template v-else-if="currentStep === 2"><h2>Customer inputs</h2><p>Only schema-defined fields and options will appear during booking.</p><ul><li v-for="field in schema?.demandFields ?? []" :key="String(field.id ?? field.fieldKey)"><strong>{{ field.label ?? field.fieldKey }}</strong><span>{{ field.valueType ?? field.value_type }}</span></li></ul><ul><li v-for="option in schema?.options ?? []" :key="String(option.id ?? option.optionKey)"><strong>{{ option.label ?? option.optionKey }}</strong><span>Optional service choice</span></li></ul></template><template v-else-if="currentStep === 3"><h2>Pricing</h2><p>Review how this offering is priced. Pricing remains calculated by the backend quote service.</p><BusinessPricingRuleEditor :rules="schema?.pricingRules ?? []" /></template><template v-else-if="currentStep === 4"><h2>Resources</h2><p>Assign people, rooms, equipment, or shared capacity only when this service needs them.</p><BusinessResourcePoolEditor v-if="resources" :profile-id="profileId()" :offering-id="selectedOfferingId" :pools="resources.pools" :resources="resources.resources" :requirements="resources.requirements" @refresh="refreshResources" /></template><template v-else><h2>Customer preview</h2><p>This is the compact booking sequence customers will see.</p><ol><li>{{ offeringDraft.title }}</li><li>Required customer inputs</li><li>Available date and valid slot</li><li>Price and conditions review</li></ol></template><AppStatus v-if="error" :message="error" tone="error" /><footer class="setup-actions"><AppButton type="button" tone="secondary" :disabled="currentStep === 0" @click="currentStep--">Back</AppButton><AppButton v-if="currentStep < steps.length - 1" type="button" tone="secondary" @click="currentStep++">Next</AppButton><AppButton type="button" tone="primary" :loading="saving" @click="saveOfferingRules">Save service rules</AppButton></footer></section></template></section></TaskSurface>
</template>

<style scoped>.service-setup{display:grid;gap:var(--space-3);max-width:70rem}.eyebrow{margin:0 0 var(--space-1);color:var(--text-soft);font-size:var(--text-size-label);font-weight:var(--text-weight-semibold);letter-spacing:var(--tracking-label);text-transform:uppercase}.service-setup h1,.service-setup h2,.service-setup p{margin:0}.service-setup h1{font-size:var(--text-size-page-title);letter-spacing:var(--tracking-tight)}.service-setup p{color:var(--text-muted);line-height:1.5}.service-setup__title-row{display:flex;align-items:end;justify-content:space-between;gap:var(--space-3)}.setup-panel{display:grid;gap:var(--space-3);padding:var(--space-4);border:1px solid var(--border-subtle);border-radius:var(--radius-surface);background:var(--surface-base)}.setup-panel label{display:grid;gap:var(--space-1);color:var(--text-muted);font-size:var(--text-size-meta);font-weight:var(--text-weight-semibold)}.setup-panel input,.setup-panel select{border:1px solid var(--control-border);border-radius:var(--radius-control);padding:var(--space-2);background:var(--control-bg);color:var(--control-ink);font:inherit}.setup-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:var(--space-2)}.setup-panel ul,.setup-panel ol{display:grid;gap:var(--space-2);margin:0;padding-left:1.2rem}.setup-panel li{display:flex;justify-content:space-between;gap:var(--space-3);padding-bottom:var(--space-2);border-bottom:1px solid var(--border-subtle)}.setup-panel li span{color:var(--text-muted);font-size:var(--text-size-meta)}.setup-actions{display:flex;justify-content:space-between;gap:var(--space-2);flex-wrap:wrap}.setup-actions>:last-child{margin-left:auto}@media(max-width:700px){.service-setup__title-row{align-items:start;flex-direction:column}.setup-grid{grid-template-columns:1fr}.setup-panel li{align-items:start;flex-direction:column}.setup-actions>:last-child{margin-left:0}}
</style>
<style scoped>
.business-template-overrides{display:grid;gap:var(--space-2);margin-bottom:var(--space-3);padding:var(--space-3);border:1px solid var(--border-subtle);border-radius:var(--radius-surface);background:var(--surface-raised)}.business-template-overrides h2,.business-template-overrides p{margin:0}.business-template-overrides p,.business-template-overrides small{color:var(--text-muted)}.business-template-overrides>div{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:var(--space-2)}.business-template-overrides label{display:grid;gap:var(--space-1);font-weight:var(--text-weight-semibold)}.business-template-overrides input,.business-template-overrides select{min-height:var(--control-height-default);padding:var(--space-1) var(--space-2);border:1px solid var(--control-border);border-radius:var(--radius-control);background:var(--control-bg);color:var(--control-ink);font:inherit}@media(max-width:700px){.business-template-overrides>div{grid-template-columns:1fr}}
</style>
<style scoped>
.business-template-library{display:grid;gap:var(--space-2);margin-bottom:var(--space-3);padding:var(--space-3);border:1px solid var(--border-subtle);border-radius:var(--radius-surface);background:var(--surface-base)}.business-template-library h2,.business-template-library p{margin:0}.business-template-library p{color:var(--text-muted)}.business-template-library__grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:var(--space-2)}.business-template-library__grid button{display:grid;gap:var(--space-1);padding:var(--space-2);border:1px solid var(--control-border);border-radius:var(--radius-control);background:var(--control-bg);color:var(--control-ink);text-align:left;font:inherit;cursor:pointer}.business-template-library__grid button.selected{border-color:var(--accent);box-shadow:0 0 0 2px var(--accent-muted)}.business-template-library__grid span{color:var(--text-muted);font-size:var(--text-size-meta)}@media(max-width:700px){.business-template-library__grid{grid-template-columns:1fr 1fr}}
</style>
